import{_ as e,o as t,c as i,a3 as s}from"./chunks/framework.ZM1D-rQ5.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1781554731000}'),o={name:"guide/introduction.md"};function n(l,a,r,d,c,h){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>FalconCMS</strong> is a full-featured, WordPress-inspired CMS package for Laravel. Drop it into any Laravel app and get a complete admin dashboard with a drag-and-drop page builder, e-commerce, multi-language support, and much more — in minutes.</p><h2 id="why-falconcms" tabindex="-1">Why FalconCMS? <a class="header-anchor" href="#why-falconcms" aria-label="Permalink to &quot;Why FalconCMS?&quot;">​</a></h2><p>Most Laravel CMS solutions are either too simple or require you to rebuild everything from scratch. FalconCMS gives you a production-ready foundation:</p><ul><li><strong>No separate installation</strong> — it&#39;s a Composer package, lives inside your Laravel app</li><li><strong>Full admin dashboard</strong> — pages, posts, custom post types, menus, media, users, settings</li><li><strong>Falcon Builder</strong> — a visual drag-and-drop page builder (think Elementor, but for Laravel)</li><li><strong>E-commerce ready</strong> — shop, cart, checkout, orders, coupons out of the box</li><li><strong>Extensible</strong> — WordPress-like hooks let you customize everything without modifying core files</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Version</th></tr></thead><tbody><tr><td>PHP</td><td>8.1+</td></tr><tr><td>Laravel</td><td>10, 11, or 12</td></tr><tr><td>Database</td><td>MySQL 5.7+ / MariaDB 10.3+ / SQLite 3.x</td></tr></tbody></table><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Install the package</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/falconcms</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Run the installer</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falcon:install</span></span></code></pre></div><p>That&#39;s it. Visit <code>/admin</code> to access your dashboard.</p><div class="tip custom-block"><p class="custom-block-title">Default credentials</p><p>After installation, use the credentials shown in your terminal output to log in.</p></div><h2 id="what-s-included" tabindex="-1">What&#39;s Included <a class="header-anchor" href="#what-s-included" aria-label="Permalink to &quot;What&#39;s Included&quot;">​</a></h2><h3 id="admin-dashboard" tabindex="-1">Admin Dashboard <a class="header-anchor" href="#admin-dashboard" aria-label="Permalink to &quot;Admin Dashboard&quot;">​</a></h3><p>A clean, fast admin interface for managing all your content, settings, and users.</p><h3 id="falcon-builder-page-builder" tabindex="-1">Falcon Builder (Page Builder) <a class="header-anchor" href="#falcon-builder-page-builder" aria-label="Permalink to &quot;Falcon Builder (Page Builder)&quot;">​</a></h3><p>Visual drag-and-drop builder with:</p><ul><li>Containers with responsive column layouts</li><li>22 built-in element types</li><li>Device-specific visibility controls</li><li>Global Sections (reusable across pages)</li><li>Container &amp; Column Library (save and reuse your designs)</li></ul><h3 id="e-commerce" tabindex="-1">E-commerce <a class="header-anchor" href="#e-commerce" aria-label="Permalink to &quot;E-commerce&quot;">​</a></h3><p>Complete shop system including products, variable products, cart, checkout, order management, and coupons.</p><h3 id="content-management" tabindex="-1">Content Management <a class="header-anchor" href="#content-management" aria-label="Permalink to &quot;Content Management&quot;">​</a></h3><ul><li>Pages, Posts, Custom Post Types</li><li>Categories, Tags, Custom Taxonomies</li><li>Revisions &amp; Autosave</li><li>Media Library</li><li>SEO meta fields</li></ul><h3 id="developer-tools" tabindex="-1">Developer Tools <a class="header-anchor" href="#developer-tools" aria-label="Permalink to &quot;Developer Tools&quot;">​</a></h3><ul><li>WordPress-like Action &amp; Filter hooks</li><li>Template tags</li><li>CLI commands</li><li>REST API (headless mode)</li></ul>`,23)])])}const m=e(o,[["render",n]]);export{p as __pageData,m as default};
